import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Define a maximum buffer size
        int bufferSize = 10;

        // Ensure that input does not exceed the buffer size
        if (name.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        // Safe copy of input into buffer
        byte[] buffer = new byte[bufferSize];
        System.arraycopy(name.getBytes(), 0, buffer, 0, Math.min(name.length(), bufferSize));

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
